import subprocess
import json
from anthropic import Anthropic

client = Anthropic()

def run_kubectl(command: str) -> str:
    """Execute a kubectl command; returns stdout+stderr."""
    try:
        result = subprocess.run(
            ["kubectl"] + command.split(),
            capture_output=True, text=True, timeout=30
        )
        return (result.stdout + result.stderr).strip() or "(empty output)"
    except subprocess.TimeoutExpired:
        return "Error: kubectl command timed out after 30 s"

